const core = require("@actions/core");
const fs = require("fs");
const util = require("util");
const path = require("path");

const appendFileAsync = util.promisify(fs.appendFile);
const writeFileAsync = util.promisify(fs.writeFile);

main().catch(error => setFailed(error.message));

async function main() {
  try {
    // `authToken` input defined in action metadata file
    const authToken = core.getInput("authToken");
    const scope = core.getInput("scope") || "";
    const registry = core.getInput("registry");
    const overwrite = core.getInput("overwrite") === "true";
    console.log(`Got a token`);
    const filePath = path.join(path.resolve(__dirname), "../../../../.npmrc");
    console.log(`Writing to ${filePath}`);
    let contents;
    contents = `
${scope === "" ? "" : scope + ":"}registry=${registry}
${registry.substr(registry.indexOf("//"))}:${
      core.getInput("tokenFormat") === "modern" ? "_authToken" : "_auth"
    }=${authToken}
`;

    if ((await exists(path)) && overwrite) {
      await appendFileAsync(filePath, contents);
    } else {
      await writeFileAsync(filePath, contents);
    }
  } catch (error) {
    core.setFailed(error.message);
  }
}

async function exists(path) {
  const accessAsync = util.promisify(fs.access);
  try {
    const err = await accessAsync(path);
    if (err) {
      return true;
    }
    return false;
  } catch (err) {
    return false;
  }
}
